mapper.select:
select n.*
from batch.workflow_node n
left join batch.workflow_definition d on d.id = n.workflow_definition_id
where 1 = 1

    and n.workflow_definition_id = #{workflowDefinitionId}


    and d.tenant_id = #{tenantId}


    and d.workflow_code = #{workflowCode}


    and n.node_code = #{nodeCode}


    and n.node_type = #{nodeType}


    and n.enabled = #{enabled}

order by n.node_order asc, n.id asc

    limit #{pageRequest.pageSize} offset (#{pageRequest.pageNo} - 1) * #{pageRequest.pageSize}

select count(1)
from batch.workflow_node n
left join batch.workflow_definition d on d.id = n.workflow_definition_id
where 1 = 1

    and n.workflow_definition_id = #{workflowDefinitionId}


    and d.tenant_id = #{tenantId}


    and d.workflow_code = #{workflowCode}


    and n.node_code = #{nodeCode}


    and n.node_type = #{nodeType}


    and n.enabled = #{enabled}

select *
from batch.workflow_node
where workflow_definition_id = #{workflowDefinitionId}
  and node_code = #{nodeCode}
limit 1
